import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("Quote — base premiums for single main items", () => {
  it.todo("should return premium 105 for a single plain sword (100 base + 5 fee)");
  it.todo("should return premium 65 for a single plain amulet (60 base + 5 fee)");
  it.todo("should return premium 85 for a single plain staff (80 base + 5 fee)");
  it.todo("should return premium 45 for a single plain potion (40 base + 5 fee)");
});

describe("Quote — component base premiums and building blocks", () => {
  it.todo("should price a single rune at 25 base premium");
  it.todo("should price 2 runes at 50 base premium (no block)");
  it.todo("should price exactly 3 runes at 60 base premium (block applies)");
  it.todo("should price 4 runes at 100 base premium (no block — block requires exactly 3)");
  it.todo("should price 7 runes at 175 base premium (no block — not exactly 3)");
  it.todo("should price 2 runes + 1 moonstone at 75 base premium (no block: different types)");
  it.todo("should price 3 runes + 3 moonstones at 120 base premium (two separate exactly-3 blocks)");
});

describe("Quote — item-specific modifiers", () => {
  it.todo("should add 50% curse surcharge to a cursed sword's base premium");
  it.todo("should add 30% high-enchantment surcharge to a sword with enchantment exactly 5");
  it.todo("should not add high-enchantment surcharge to a sword with enchantment 4");
  it.todo("should apply both curse and high-enchantment surcharges to a cursed highly-enchanted sword");
});

describe("Quote — policy-wide modifiers", () => {
  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years with MHPCO");
  it.todo("should not apply loyalty discount for a customer with fewer than 2 years");
  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
  it.todo("should apply 15% follow-up discount on the customer's second quote in the scenario");
});

describe("Quote — modifier scope on multi-item policies", () => {
  it.todo("should apply curse surcharge only to the cursed item's base premium, not the policy total (cursed sword + plain amulet → 210 before fee)");
});

describe("Quote — rounding", () => {
  it.todo("should round the final premium up to whole G in MHPCO's favor (197.5 → 198)");
});

describe("Quote — integration examples", () => {
  it.todo("should compute premium 165 for newcomer's cursed steel sword (enchantment 3, 0 years, first quote)");
  it.todo("should compute premium 160 for long-standing customer's second quote (cursed steel sword enchantment 7, 3 years)");
});

describe("Quote — edge cases", () => {
  it.todo("should return premium 5 for an empty item list (only the processing fee)");
});

describe("Claim — standard reimbursement (no special clauses)", () => {
  it.todo("should pay out 400 for a regular steel sword (enchantment 3) damaged 500 (damage minus 100 deductible)");
  it.todo("should pay out 100 for a rune damaged 200 (no special clause; damage minus deductible)");
});

describe("Claim — high-enchantment and dragon-material clauses", () => {
  it.todo("should pay out 400 for a steel sword enchantment 9 damaged 1000 (50% then deductible)");
  it.todo("should pay out 700 for a dragon-material sword enchantment 5 damaged 800 (full then deductible)");
  it.todo("should pay out 400 for a dragon-material sword enchantment 8 damaged 1000 (50% rule wins, then deductible)");
  it.todo("should pay out 400 for a dragon-material sword enchantment 9 damaged 1000 (50% rule wins over dragon)");
});

describe("Claim — deductible per damage event", () => {
  it.todo("should apply the deductible once per damaged item (sword 500 + amulet 300 → 600)");
  it.todo("should apply a separate deductible to each entry when two swords of the same type are damaged");
});

describe("Claim — payout cap", () => {
  it.todo("should base the cap on unmodified insurance values (sword + amulet → cap 3200)");
  it.todo("should base the cap on insurance values not block-discounted premium (sword + 3 runes → insurance sum 1750)");
  it.todo("should cap the first of two successive claims at the remaining cap (sword cap 2000, claim 1500 → payout 1400, remainingCap 600)");
  it.todo("should reduce a later claim to the remaining cap (second claim 1500 → payout 600, remainingCap 0)");
});

describe("Claim — error cases", () => {
  it.todo("should reject a claim referencing a damage item not in the policy (e.g. amulet damaged when only a sword insured)");
  it.todo("should reject a claim with more entries of a type than the policy covers (two sword damages, one sword insured)");
  it.todo("should reject a claim with an unknown damage item type");
  it.todo("should reject a claim with a negative damage amount");
});

describe("Quote — error cases", () => {
  it.todo("should reject a quote containing an item with an unknown type");
});
